=Transform this Figma-exported HTML/CSS into clean, production-ready email HTML. Apply all POUR accessibility rules and dark mode support as described in your instructions.

Here is the Figma HTML export:

{{ $json['Figma HTML Export'] }}

parameters.jsCode:
// Accessibility & Quality Tests
// Runs automated checks on the cleaned HTML

const html = $input.first().json.output || $input.first().json.text || '';
const formData = $('Submit Figma HTML').first().json;
const campaignName = formData['Campaign Name'] || 'Untitled';
const brandGuidelines = formData['Brand Guidelines'] || '';
const proofEmail = formData['Proof Email Address'] || '';
const jiraProject = formData['Jira Project Key'] || '';

const issues = [];
const warnings = [];
const passed = [];

// === POUR: Robust - Language attribute ===
if (/<html[^>]*lang\s*=/i.test(html)) {
  passed.push('HTML lang attribute present');
} else {
  issues.push('Missing lang attribute on <html> tag');
}

// === POUR: Understandable - Heading hierarchy ===
const headingRegex = /<h([1-6])[^>]*>/gi;
let match;
const headingLevels = [];
while ((match = headingRegex.exec(html)) !== null) {
  headingLevels.push(parseInt(match[1]));
}
let headingOk = true;
for (let i = 1; i < headingLevels.length; i++) {
  if (headingLevels[i] > headingLevels[i - 1] + 1) {
    issues.push('Heading hierarchy skip: h' + headingLevels[i - 1] + ' to h' + headingLevels[i]);
    headingOk = false;
  }
}
if (headingOk && headingLevels.length > 0) {
  passed.push('Heading hierarchy is correct');
}

// === POUR: Perceivable - Image alt text ===
const imgRegex = /<img[^>]*>/gi;
const imgs = html.match(imgRegex) || [];
let imgIssues = 0;
for (const img of imgs) {
  if (!/alt\s*=/i.test(img)) {
    issues.push('Image missing alt attribute');
    imgIssues++;
  }
}
if (imgIssues === 0 && imgs.length > 0) {
  passed.push('All images have alt attributes (' + imgs.length + ' images)');
}

// === Dark Mode ===
if (/@media[^{]*prefers-color-scheme\s*:\s*dark/i.test(html)) {
  passed.push('Dark mode media query detected');
} else {
  warnings.push('No @media (prefers-color-scheme: dark) detected');
}

// === POUR: Robust - Layout table roles ===
const tableRegex = /<table[^>]*>/gi;
const tables = html.match(tableRegex) || [];
let tableIssues = 0;
for (const table of tables) {
  if (!/role\s*=\s*["']presentation["']/i.test(table)) {
    warnings.push('Layout table may need role="presentation"');
    tableIssues++;
  }
}
if (tableIssues === 0 && tables.length > 0) {
  passed.push('All tables have role="presentation" (' + tables.length + ' tables)');
}

// === POUR: Perceivable - Font sizes ===
const fsRegex = /font-size\s*:\s*(\d+(?:\.\d+)?)\s*px/gi;
let fsMatch;
let smallFonts = 0;
while ((fsMatch = fsRegex.exec(html)) !== null) {
  const size = parseFloat(fsMatch[1]);
  if (size < 14) {
    warnings.push('Font size ' + size + 'px is below 14px minimum');
    smallFonts++;
  }
}
if (smallFonts === 0) {
  passed.push('All font sizes meet 14px minimum');
}

// === POUR: Understandable - Proper list markup ===
const hasBulletChars = /[\u2022\u25CF\u25E6\u25AA\u25AB\u2023\u2043]/g.test(html);
const hasListMarkup = /<[uo]l[^>]*>/i.test(html);
if (hasBulletChars && !hasListMarkup) {
  issues.push('Manual bullet characters found without proper <ul>/<ol> markup');
} else {
  passed.push('No manual bullet characters detected');
}

// === POUR: Operable - Link text quality ===
const linkRegex = /<a[^>]*>([^<]*)<\/a>/gi;
let linkMatch;
const badLinkTexts = ['click here', 'read more', 'learn more', 'here', 'link', 'more'];
while ((linkMatch = linkRegex.exec(html)) !== null) {
  const text = linkMatch[1].trim().toLowerCase();
  if (badLinkTexts.includes(text)) {
    warnings.push('Non-descriptive link text: "' + linkMatch[1].trim() + '"');
  }
}

// === Email best practices ===
if (/<!DOCTYPE html>/i.test(html)) {
  passed.push('HTML5 DOCTYPE present');
} else {
  warnings.push('Missing HTML5 DOCTYPE declaration');
}

if (/meta[^>]*charset/i.test(html)) {
  passed.push('Meta charset present');
} else {
  warnings.push('Missing meta charset declaration');
}

if (/meta[^>]*viewport/i.test(html)) {
  passed.push('Meta viewport present');
} else {
  warnings.push('Missing meta viewport for mobile responsiveness');
}

// === Build summary ===
const allPassed = issues.length === 0;
const summary = allPassed
  ? 'ALL TESTS PASSED - ' + passed.length + ' checks OK, ' + warnings.length + ' warnings'
  : 'ISSUES FOUND - ' + issues.length + ' issues, ' + warnings.length + ' warnings, ' + passed.length + ' passed';

return [{
  json: {
    html,
    campaignName,
    brandGuidelines,
    proofEmail,
    jiraProject,
    testsPassed: allPassed,
    testReport: {
      summary,
      issueCount: issues.length,
      warningCount: warnings.length,
      passedCount: passed.length,
      issues,
      warnings,
      passed
    }
  }
}];

