// Build Final Delivery Package
// Assembles all results into a structured output for delivery

const brandOutput = $input.first().json.output || $input.first().json.text || 'No brand validation performed';

// Get data passed through from earlier nodes
const testNode = $('Accessibility & Quality Tests').first().json;
const html = testNode.html || '';
const campaignName = testNode.campaignName || 'Untitled Campaign';
const proofEmail = testNode.proofEmail || '';
const jiraProject = testNode.jiraProject || '';
const testReport = testNode.testReport || {};

// Build the proof email body with embedded HTML preview
const timestamp = new Date().toISOString().split('T')[0];

const emailBody = `
<h2>Email Campaign Proof: ${campaignName}</h2>
<p><strong>Date:</strong> ${timestamp}</p>
<p><strong>Status:</strong> ${testReport.summary || 'N/A'}</p>

<h3>Test Results</h3>
<p><strong>Passed:</strong> ${testReport.passedCount || 0} checks</p>
<p><strong>Issues:</strong> ${testReport.issueCount || 0}</p>
<p><strong>Warnings:</strong> ${testReport.warningCount || 0}</p>
${testReport.issues && testReport.issues.length > 0 ? '<ul>' + testReport.issues.map(i => '<li style="color:red">' + i + '</li>').join('') + '</ul>' : '<p style="color:green">No issues found!</p>'}
${testReport.warnings && testReport.warnings.length > 0 ? '<h4>Warnings:</h4><ul>' + testReport.warnings.map(w => '<li style="color:orange">' + w + '</li>').join('') + '</ul>' : ''}

<h3>Brand Validation</h3>
<pre style="background:#f5f5f5;padding:16px;border-radius:8px;white-space:pre-wrap;">${brandOutput}</pre>

<h3>HTML Preview</h3>
<p>The production HTML is attached / included below for your review.</p>
<hr>
${html}
`;

const jiraSummary = '[Email Campaign] ' + campaignName + ' - ' + timestamp;
const jiraDescription = 'Campaign: ' + campaignName + '\n\n'
  + 'Test Results: ' + (testReport.summary || 'N/A') + '\n\n'
  + 'Brand Validation:\n' + brandOutput.substring(0, 1000) + '\n\n'
  + 'Issues: ' + (testReport.issues ? testReport.issues.join(', ') : 'None') + '\n'
  + 'Warnings: ' + (testReport.warnings ? testReport.warnings.join(', ') : 'None');

return [{
  json: {
    campaignName,
    proofEmail,
    jiraProject,
    finalHtml: html,
    emailSubject: 'Email Proof: ' + campaignName + ' - ' + timestamp,
    emailBody,
    jiraSummary,
    jiraDescription,
    brandValidation: brandOutput,
    testReport,
    timestamp
  }
}];
